// Extract all fields from the webhook input
const body = $input.first()?.json || {};

return [{
  json: {
    chatInput: body.chatInput || body.message || '',
    sessionId: body.sessionId || 'anonymous',
    history: body.history || [],
    resumeText: body.resumeText || '',
    fileName: body.fileName || ''
  }
}];

const body = $input.first()?.json?.body || {};
const keyword = body.keyword || body.query || body.search || 'Software Developer';
const location = body.location || body.city || 'India';
const resultsPerPage = Math.min(body.resultsPerPage || body.limit || 10, 50);

return [{
  json: {
    keyword,
    location,
    resultsPerPage,
    what: keyword,
    where: location
  }
}];

const response = $input.first()?.json || {};
const results = Array.isArray(response.results) ? response.results : [];

if (results.length === 0) {
  return [{ json: { output: 'No jobs found for this search. Try different keywords or location.', jobs: [] } }];
}

const jobs = results.map((job, i) => ({
  title: job.title || 'Unknown',
  company: job.company?.display_name || 'Unknown Company',
  location: job.location?.display_name || 'India',
  salaryMin: job.salary_min,
  salaryMax: job.salary_max,
  salaryIsEstimated: job.salary_is_predicted === '1',
  description: (job.description || '').substring(0, 300) + '...',
  applyUrl: job.redirect_url || '',
  postedDate: job.created || '',
  category: job.category?.label || '',
  contractType: job.contract_type || '',
  contractTime: job.contract_time || ''
}));

let output = `🎯 Found ${jobs.length} jobs:\n\n`;
jobs.forEach((job, i) => {
  output += `${i + 1}. **${job.title}** at ${job.company}\n`;
  output += `   📍 ${job.location}\n`;
  if (job.salaryMin || job.salaryMax) {
    output += `   💰 ₹${job.salaryMin?.toLocaleString() || '?'} - ₹${job.salaryMax?.toLocaleString() || '?'}${job.salaryIsEstimated ? ' (estimated)' : ''}\n`;
  }
  output += `   📝 ${job.description}\n`;
  output += `   🔗 Apply: ${job.applyUrl}\n\n`;
});

return [{ json: { output, jobs } }];

