const aiResponse = $input.first()?.json || {};

function extractContent(raw) {
  return raw?.choices?.[0]?.message?.content ?? '';
}

function parseJson(content) {
  try {
    const cleaned = String(content).replace(/```json/gi, '').replace(/```/g, '').trim();
    const match = cleaned.match(/\{[\s\S]*\}/);
    return JSON.parse(match ? match[0] : cleaned);
  } catch (e) {
    return { error: 'Failed to parse resume', skills: [], technicalSkills: [] };
  }
}

const parsed = parseJson(extractContent(aiResponse));

let output = `✅ **Resume Analysis Complete!**\n\n`;
output += `👤 **Name:** ${parsed.fullName || 'Not found'}\n`;
output += `📧 **Email:** ${parsed.email || 'Not found'}\n`;
output += `🎯 **Primary Role:** ${parsed.primaryRole || 'Not specified'}\n`;
output += `💼 **Experience:** ${parsed.yearsOfExperience || 0} years\n\n`;
output += `🔑 **Skills:** ${(parsed.technicalSkills || []).slice(0, 10).join(', ')}\n\n`;
output += `💡 **Recommendation:** Based on your profile, I recommend searching for '${parsed.primaryRole || 'Software Developer'}' positions. Use the search_jobs tool to find matching opportunities!`;

return [{ json: { output, parsed } }];

