const aiResponse = $input.first()?.json || {};
const webhookData = $items('Generate Email Webhook1')[0]?.json?.body || {};

function extractContent(raw) {
  return raw?.choices?.[0]?.message?.content ?? 'Failed to generate email';
}

const emailBody = extractContent(aiResponse);
const jobTitle = webhookData.jobTitle || 'Job Position';
const company = webhookData.company || 'Company';
const candidateName = webhookData.candidateName || 'Candidate';

return [{
  json: {
    subject: `Application for ${jobTitle} Position at ${company}`,
    emailBody,
    company,
    jobTitle,
    candidateName,
    to: webhookData.companyEmail || '',
    cc: 'sairaj.nadaf@gmail.com'
  }
}];

const emailResult = $input.first()?.json || {};

return [{
  json: {
    output: `✅ **Email Sent Successfully!**\n\n📧 **To:** ${emailResult.to || 'Company'}\n📋 **Subject:** ${emailResult.subject || 'Job Application'}\n👤 **CC:** sairaj.nadaf@gmail.com\n\nYour application has been sent! Good luck! 🚀`
  }
}];
